 10	  DescriptionListTermHelpText,
 11	  DescriptionListTermHelpTextButton,
 12	  Flex,
 13	  FlexItem,
 14	  Popover,
 15	} from '@patternfly/react-core';
 16	import { PencilAltIcon } from '@patternfly/react-icons';
 17	
 18	type WizardDescriptionItemProps = {
 19	  /** additional className */
 20	  className?: string;
 21	  /** count of items in the description list */
 22	  count?: number | string;
 23	  /** description */
 24	  description?: ReactNode;
 25	  /** helper popover. the popover will not be available if onTitleClick is present */
 26	  helperPopover?: {
 27	    content: ReactNode;
 28	    header: ReactNode;
 29	  };
 30	  /** help text icon */
 31	  helpTextIcon?: ReactNode;
 32	  /** disabled state of the description group */
 33	  isDisabled?: boolean;
 34	  /** is the description group editable */
 35	  isEdit?: boolean;
 36	  label?: ReactNode;
 37	  /** onClick callback for the edit button */
 38	  onEditClick?: () => void;
 39	  /** onClick callback for the title */
 40	  onTitleClick?: () => void;
 41	  /** show edit button besides title */
 42	  showEditOnTitle?: boolean;
 43	  /** date-test-id of the description group */
 44	  testId?: string;
 45	  /** title */
 46	  title: string;
 47	};
 48	
 49	export const WizardDescriptionItem: FC<WizardDescriptionItemProps> = React.memo(
 50	  ({
 51	    className,
 52	    count,
 53	    description,
 54	    helperPopover,
 55	    helpTextIcon,
 56	    isDisabled,
 57	    isEdit,
 58	    label,
 59	    onEditClick,
 60	    onTitleClick,
 61	    showEditOnTitle,
 62	    testId,
 63	    title,
 64	  }) => {
 65	    const { t } = useKubevirtTranslation();
 66	    const titleWithCount = title.concat(count ? ` (${count})` : '');
 67	    const getItemHeader = () => {
 68	      if (onTitleClick)
 69	        return (
 70	          <Button isDisabled={isDisabled} isInline onClick={onTitleClick} variant="link">
 71	            <DescriptionListTerm>{titleWithCount}</DescriptionListTerm>
 72	          </Button>
 73	        );
 74	
 75	      if (helperPopover) {
 76	        return (
 77	          <Popover bodyContent={helperPopover?.content} headerContent={helperPopover?.header}>
 78	            <DescriptionListTermHelpTextButton className="pf-v6-c-description-list__text">
 79	              {' '}
 80	              {title}{' '}
 81	            </DescriptionListTermHelpTextButton>
 82	          </Popover>
 83	        );
 84	      }
 85	
 86	      return (
 87	        <DescriptionListTerm icon={helpTextIcon}>
 88	          {titleWithCount} {label}
 89	        </DescriptionListTerm>
 90	      );
 91	    };
 92	
 93	    return (
 94	      <DescriptionListGroup className={classnames('pf-v6-c-description-list__group', className)}>
 95	        <DescriptionListTermHelpText className="pf-v6-c-description-list__term">
 96	          <Flex
 97	            className="wizard-description-item__title"
 98	            justifyContent={{ default: 'justifyContentFlexStart' }}
 99	          >
100	            <FlexItem>{getItemHeader()}</FlexItem>
101	            {isEdit && showEditOnTitle && (
102	              <FlexItem>
103	                <Button
104	                  icon={<PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />}
105	                  data-test-id={`${testId}-edit`}
106	                  isDisabled={isDisabled}
107	                  isInline
108	                  onClick={onEditClick}
109	                  type="button"
110	                  variant="link"
111	                >
112	                  {t('Edit')}
113	                </Button>
114	              </FlexItem>
115	            )}
116	          </Flex>
117	        </DescriptionListTermHelpText>
118	        {isEdit && !showEditOnTitle ? (
119	          <DescriptionListDescription>
120	            <Button
121	              icon={<PencilAltIcon className="co-icon-space-l pf-v6-c-button-icon--plain" />}
122	              className="pf-v6-c-description-list__description"
123	              data-test-id={`${testId}-edit`}
124	              isDisabled={isDisabled}
125	              isInline
126	              onClick={onEditClick}
127	              type="button"
128	              variant="link"
129	            >
130	              {description ?? <span className="text-muted">{t('Not available')}</span>}
131	            </Button>
132	          </DescriptionListDescription>
133	        ) : (
134	          <DescriptionListDescription data-test-id={testId} className="pf-v6-c-description-list__description">
135	            {description ?? <span className="text-muted">{t('Not available')}</span>}
136	          </DescriptionListDescription>
137	        )}
138	      </DescriptionListGroup>
139	    );
140	  },
141	);
142	WizardDescriptionItem.displayName = 'WizardDescriptionItem';

